mapper.select:
SELECT 
FROM vso_callback_log t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.order_id = #{orderId}


    AND t.business_type = #{businessType}


    AND t.callback_status_value = #{callbackStatusValue}

ORDER BY t.id DESC

